import{_ as t,o as r,c as o,a2 as a}from"./chunks/framework.DpRDjl8b.js";const h=JSON.parse('{"title":"Matrice de reutilisation — NovelTrad 2.0 vs projets similaires","description":"","frontmatter":{},"headers":[],"relativePath":"REUSE_MAP.md","filePath":"REUSE_MAP.md","lastUpdated":1784751030000}'),i={name:"REUSE_MAP.md"};function l(n,e,s,d,u,c){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="matrice-de-reutilisation-—-noveltrad-2-0-vs-projets-similaires" tabindex="-1">Matrice de reutilisation — NovelTrad 2.0 vs projets similaires <a class="header-anchor" href="#matrice-de-reutilisation-—-noveltrad-2-0-vs-projets-similaires" aria-label="Permalink to &quot;Matrice de reutilisation — NovelTrad 2.0 vs projets similaires&quot;">​</a></h1><blockquote><p>Objectif : pour chaque feature cle de NovelTrad, identifier un projet open source existant dont on peut s&#39;inspirer ou reutiliser des patterns, afin de creer le minimum de code maison.</p></blockquote><hr><h2 id="legende" tabindex="-1">Legende <a class="header-anchor" href="#legende" aria-label="Permalink to &quot;Legende&quot;">​</a></h2><ul><li><strong>Pattern</strong> : concept/architecture a reprendre tel quel.</li><li><strong>Librairie</strong> : dependance npm/pip directement utilisable.</li><li><strong>Inspiration</strong> : approche a adapter, pas de copie directe.</li><li><strong>Must-study</strong> : projet a etudier en priorite car tres proche.</li></ul><hr><h2 id="_1-orchestration-multi-agent" tabindex="-1">1. Orchestration multi-agent <a class="header-anchor" href="#_1-orchestration-multi-agent" aria-label="Permalink to &quot;1. Orchestration multi-agent&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Workflow declaratif, agents en sequence</td><td><strong>honya</strong> (Rust CLI/TUI)</td><td>Pattern Orchestrator / Translator / Reviewer ; boucle review → correction.</td><td>Must-study</td></tr><tr><td>Pipeline Parser / Translator / Validator / Summarizer / Terminology / Generator</td><td><strong>LaTeXTrans</strong> (academique)</td><td>Architecture des roles d&#39;agents ; QA agent, glossaire agent, validation pipeline.</td><td>Must-study</td></tr><tr><td>Traduction litteraire longue, coherence stylistique</td><td><strong>TransAgents</strong> (recherche)</td><td>Idees de coherence long terme et evaluation humaine + LLM.</td><td>Inspiration</td></tr><tr><td>RAG repository-aware, contexte global du roman</td><td><strong>RepoTransAgent</strong> (recherche)</td><td>Indexation semantique des chapitres precedents pour enrichir le contexte.</td><td>Inspiration</td></tr></tbody></table><h2 id="_2-export-epub-parsing" tabindex="-1">2. Export EPUB &amp; parsing <a class="header-anchor" href="#_2-export-epub-parsing" aria-label="Permalink to &quot;2. Export EPUB &amp; parsing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Traduction EPUB complete, affichage bilingue</td><td><strong>epub-translator</strong> (OOMOL Lab), <strong>PolyglotShelf</strong></td><td>Structure de pipeline EPUB ; mode bilingue ; UX lecteur ; file durable ; merge incremental.</td><td>Must-study</td></tr><tr><td>Multi-provider IA + EPUB bilingue</td><td><strong>bbook-maker</strong> (PyPI)</td><td>Gestion multi-modeles ; simplicite d&#39;UX.</td><td>Inspiration</td></tr><tr><td>Scrape web novel → EPUB auto</td><td><strong>gptwntranslator</strong></td><td>MVP ultra simple &quot;scrape → translate → export&quot;.</td><td>Inspiration</td></tr><tr><td>Parsing EPUB sans casser le markup</td><td><strong>Ebook Translator for Calibre</strong></td><td>Extraction/recompilation propre des balises HTML dans l&#39;EPUB.</td><td>Must-study</td></tr><tr><td>Formats varies, preservation formatage, checkpoints</td><td><strong>TranslateBooksWithLLMs</strong>, <strong>PolyglotShelf</strong></td><td>Robustesse formatage, reprise sur incident, pas de limite taille, file durable.</td><td>Must-study</td></tr><tr><td>Architecture Docker + API REST + file durable</td><td><strong>PolyglotShelf</strong></td><td>Service Docker, file SQLite durable, merge incremental de gros EPUB, API REST.</td><td>Must-study</td></tr></tbody></table><h2 id="_3-glossaire-translation-memory" tabindex="-1">3. Glossaire &amp; Translation Memory <a class="header-anchor" href="#_3-glossaire-translation-memory" aria-label="Permalink to &quot;3. Glossaire &amp; Translation Memory&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Glossaire verrouille + TM</td><td><strong>OmegaT</strong> (CAT open source)</td><td>Memoire de traduction mature, glossaires, dictionnaires locaux.</td><td>Must-study</td></tr><tr><td>Glossaire robuste, 40+ providers, gestion quotas</td><td><strong>Glossarion</strong> (PySide6 GUI)</td><td>Gestion multi-modeles, terminologie verrouillee, UI riche.</td><td>Must-study</td></tr><tr><td>Projet resumable par episode, file d&#39;attente QA, termes forbidden/locked</td><td><strong>NovelTrans</strong> (SaaS)</td><td>Structure projet par episode, QA queue, termes forbidden/locked.</td><td>Must-study</td></tr><tr><td>Feedback utilisateur 👍/👎, comparateur versions, footnotes</td><td><strong>LexiconForge</strong> (Web App)</td><td>Systeme de feedback, comparateur source/brute/IA, exports enrichis.</td><td>Inspiration</td></tr></tbody></table><h2 id="_4-ui-workspaces-cote-a-cote" tabindex="-1">4. UI / Workspaces / Cote a cote <a class="header-anchor" href="#_4-ui-workspaces-cote-a-cote" aria-label="Permalink to &quot;4. UI / Workspaces / Cote a cote&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Workspaces par roman avec parametres modeles</td><td><strong>AnythingLLM Desktop</strong></td><td>Gestion modeles locaux, RAG, historique SQLite, workspaces.</td><td>Inspiration</td></tr><tr><td>UI parametres modele par workspace</td><td><strong>Chatbox</strong></td><td>Logique de &quot;workspace&quot; avec temperature, context length, system prompts.</td><td>Inspiration</td></tr><tr><td>Affichage cote a cote source/traduction</td><td><strong>Sugoi Toolkit</strong></td><td>Decoupage phrases, file d&#39;attente, affichage cote a cote.</td><td>Inspiration</td></tr><tr><td>Simplicite extreme, scraping, glossaire auto</td><td><strong>OpenNovel</strong> (extension navigateur)</td><td>Zero configuration, chunking intelligent.</td><td>Inspiration</td></tr></tbody></table><h2 id="_5-modeles-nmt-locaux-comparateurs" tabindex="-1">5. Modeles NMT locaux &amp; comparateurs <a class="header-anchor" href="#_5-modeles-nmt-locaux-comparateurs" aria-label="Permalink to &quot;5. Modeles NMT locaux &amp; comparateurs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Modeles NMT locaux Marian, offline</td><td><strong>OPUS-CAT</strong></td><td>Option modeles NMT locaux pour confidentialite/performance.</td><td>Inspiration (v1.5+)</td></tr><tr><td>Comparaison parallele de providers, benchmark</td><td><strong>multranslate</strong></td><td>Dashboard qualite, comparaison providers.</td><td>Inspiration (v1.5+)</td></tr><tr><td>Framework NMT avec UI training/eval</td><td><strong>adaptNMT</strong> (recherche)</td><td>Metriques integrees, scoring automatique.</td><td>Inspiration (v1.5+)</td></tr></tbody></table><h2 id="_6-parsing-de-fichiers-source" tabindex="-1">6. Parsing de fichiers source <a class="header-anchor" href="#_6-parsing-de-fichiers-source" aria-label="Permalink to &quot;6. Parsing de fichiers source&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>DOCX → HTML → Markdown</td><td><strong>mammoth.js</strong></td><td>Librairie npm directement utilisable.</td><td>Librairie</td></tr><tr><td>EPUB parsing</td><td><strong>@likecoin/epub-ts</strong> ou <strong>epubjs</strong></td><td>Verifier la maturite ; sinon utiliser <code>adm-zip</code> + <code>jsdom</code>/<code>cheerio</code>.</td><td>A valider</td></tr><tr><td>Detection encodage</td><td><strong>chardet</strong> / <strong>iconv-lite</strong></td><td>Librairies npm standards.</td><td>Librairie</td></tr><tr><td>Detection langue</td><td><strong>franc</strong></td><td>Librairie npm directement utilisable.</td><td>Librairie</td></tr><tr><td>Decoupage phrase par langue</td><td><strong>franc</strong> + custom, ou librairies NLP cible</td><td>Tokenisation basee sur la ponctuation cible.</td><td>Librairie / custom</td></tr></tbody></table><h2 id="_7-export" tabindex="-1">7. Export <a class="header-anchor" href="#_7-export" aria-label="Permalink to &quot;7. Export&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Generation DOCX</td><td><strong>docx</strong> (dolanmiu)</td><td>Librairie npm directement utilisable.</td><td>Librairie</td></tr><tr><td>Generation EPUB</td><td><strong>epub-gen-memory</strong></td><td>Verifier la maturite ; alternative : generation manuelle avec <code>archiver</code>.</td><td>A valider</td></tr><tr><td>Validation EPUB</td><td><strong>epubcheck</strong> (Java)</td><td>Lancer en sous-processus si disponible.</td><td>Outil externe</td></tr><tr><td>EPUB mode bilingue</td><td><strong>epub-translator</strong>, <strong>bbook-maker</strong></td><td>Structure paragraphes source/cote a cote ou alternes.</td><td>Must-study</td></tr></tbody></table><h2 id="_8-developpement-distribution" tabindex="-1">8. Developpement &amp; distribution <a class="header-anchor" href="#_8-developpement-distribution" aria-label="Permalink to &quot;8. Developpement &amp; distribution&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Build/packaging Electron</td><td><strong>electron-builder</strong></td><td>Outil standard.</td><td>Librairie</td></tr><tr><td>Auto-update</td><td><strong>electron-updater</strong></td><td>Integration standard avec electron-builder.</td><td>Librairie</td></tr><tr><td>Tests E2E Electron</td><td><strong>Playwright + @playwright/test</strong></td><td>Support experimental d&#39;Electron.</td><td>Librairie</td></tr><tr><td>Tests unitaires</td><td><strong>Vitest</strong></td><td>Test runner rapide pour Node/Vue.</td><td>Librairie</td></tr><tr><td>Code signing / notarization</td><td><strong>electron-builder</strong> docs + <strong>Apple notarytool</strong></td><td>Configuration CSC_LINK, APPLE_ID, notarytool.</td><td>Documentation</td></tr></tbody></table><h2 id="_9-securite-confidentialite" tabindex="-1">9. Securite &amp; confidentialite <a class="header-anchor" href="#_9-securite-confidentialite" aria-label="Permalink to &quot;9. Securite &amp; confidentialite&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature NovelTrad</th><th>Projets similaires</th><th>Ce qu&#39;on peut recuperer</th><th>Priorite</th></tr></thead><tbody><tr><td>Stockage securise des cles API</td><td><strong>keytar</strong> (keyring OS)</td><td>Librairie npm standard pour Credential Locker / Keychain / libsecret.</td><td>Librairie</td></tr><tr><td>Chiffrement fallback cles API</td><td>Node.js <code>crypto</code> AES-256-GCM</td><td>Pattern documente dans <code>21-Security.md</code>.</td><td>Pattern</td></tr><tr><td>Isolation renderer/preload</td><td>Electron security baseline officielle</td><td><code>contextIsolation</code>, <code>nodeIntegration: false</code>, <code>contextBridge</code>.</td><td>Pattern</td></tr><tr><td>Validation de chemins (path traversal)</td><td>Patterns Node.js + tests unitaires</td><td><code>path.resolve</code> + verification prefixe.</td><td>Pattern</td></tr></tbody></table><hr><h2 id="detail-des-parties-reutilisables-par-projet" tabindex="-1">Detail des parties reutilisables par projet <a class="header-anchor" href="#detail-des-parties-reutilisables-par-projet" aria-label="Permalink to &quot;Detail des parties reutilisables par projet&quot;">​</a></h2><p>Cette section precise, pour chaque projet identifie, <strong>quelles fonctions, patterns ou librairies</strong> sont concretement recuperables afin de minimiser le code maison.</p><h3 id="projets-must-study" tabindex="-1">Projets Must-study <a class="header-anchor" href="#projets-must-study" aria-label="Permalink to &quot;Projets Must-study&quot;">​</a></h3><h4 id="honya-rust-cli-tui" tabindex="-1">honya (Rust CLI/TUI) <a class="header-anchor" href="#honya-rust-cli-tui" aria-label="Permalink to &quot;honya (Rust CLI/TUI)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Architecture a 3 roles : <code>Orchestrator</code>, <code>Translator</code>, <code>Reviewer</code>.</li><li>Boucle <code>review → correction</code> avant validation finale.</li><li>Glossaire et personnages maintenus dans le contexte de l&#39;orchestrateur.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Decomposer l&#39;agent <code>Reviewer</code> de honya en <code>ConsistencyAgent</code>, <code>QAAgent</code>, <code>PolishAgent</code>.</li><li>Ajouter un mecanisme de retry automatique quand un step retourne un score insuffisant.</li><li>Voir <code>docs/volumes/07-Workflow.md</code>, <code>08-Agents.md</code>.</li></ul></li></ul><h4 id="latextrans-framework-academique-multi-agent" tabindex="-1">LaTeXTrans (framework academique multi-agent) <a class="header-anchor" href="#latextrans-framework-academique-multi-agent" aria-label="Permalink to &quot;LaTeXTrans (framework academique multi-agent)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Roles d&#39;agents : <code>Parser</code>, <code>Translator</code>, <code>Validator</code>, <code>Summarizer</code>, <code>Terminology</code>, <code>Generator</code>.</li><li>Agent <code>Summarizer</code> qui maintient un resume global du document.</li><li>Agent <code>Validator</code> / QA formel avec schema de sortie JSON.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Renommer / aligner les agents existants sur ces responsabilites precises.</li><li>Ajouter un agent <code>Summarizer</code> (v1.5) pour maintenir un resume du roman et ameliorer la coherence long terme.</li><li>Formaliser le <code>QAAgent</code> comme un validateur independant avec sortie JSON structurée.</li><li>Voir <code>docs/volumes/08-Agents.md</code>, <code>12-Quality.md</code>.</li></ul></li></ul><h4 id="epub-translator-oomol-lab" tabindex="-1">epub-translator (OOMOL Lab) <a class="header-anchor" href="#epub-translator-oomol-lab" aria-label="Permalink to &quot;epub-translator (OOMOL Lab)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Pipeline EPUB complet : extraction → traduction → recompilation.</li><li>Mode bilingue (original + traduction) preserve dans le fichier EPUB.</li><li>Multi-provider LLM configurable.</li><li>UX lecteur avec navigation par chapitre.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Structurer l&#39;export EPUB en deux pistes (source + cible) ou alternance de paragraphes.</li><li>Conserver les metadonnees OPF et la table des matieres.</li><li>Permettre un mode &quot;lecture bilingue&quot; dans l&#39;UI.</li><li>Voir <code>docs/volumes/13-Export.md</code>.</li></ul></li></ul><h4 id="ebook-translator-for-calibre" tabindex="-1">Ebook Translator for Calibre <a class="header-anchor" href="#ebook-translator-for-calibre" aria-label="Permalink to &quot;Ebook Translator for Calibre&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Parsing EPUB sans destruction du markup HTML.</li><li>Recompilation fidèle des balises, styles CSS, metadonnees.</li><li>Gestion des tags inlines (<code>&lt;span&gt;</code>, <code>&lt;em&gt;</code>, <code>&lt;strong&gt;</code>) pendant la traduction.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Utiliser une strategie de parsing DOM (<code>cheerio</code> / <code>jsdom</code>) pour extraire le texte sans perdre les balises.</li><li>Mapper les fragments traduits aux noeuds d&#39;origine.</li><li>Voir <code>docs/volumes/05-Project-Management.md</code>, <code>13-Export.md</code>.</li></ul></li></ul><h4 id="omegat-cat-open-source" tabindex="-1">OmegaT (CAT open source) <a class="header-anchor" href="#omegat-cat-open-source" aria-label="Permalink to &quot;OmegaT (CAT open source)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Memoire de traduction au format TMX.</li><li>Glossaires avec termes verrouilles.</li><li>Segmentation fine au niveau phrase.</li><li>Interface cote-a-cote source/cible avec statut segment par segment.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Implementer l&#39;import/export TMX (<code>docs/volumes/09-Translation-Memory.md</code>).</li><li>Appliquer les termes verrouilles imperativement (<code>docs/volumes/10-Lexicon.md</code>).</li><li>Segmenter au niveau phrase avant stockage TM.</li><li>S&#39;inspirer de l&#39;UI cote-a-cote segmentee pour l&#39;ecran de relecture.</li></ul></li></ul><h4 id="glossarion-pyside6-gui" tabindex="-1">Glossarion (PySide6 GUI) <a class="header-anchor" href="#glossarion-pyside6-gui" aria-label="Permalink to &quot;Glossarion (PySide6 GUI)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Gestion de 40+ providers (OpenAI, Anthropic, Gemini, OpenRouter, Ollama, etc.).</li><li>Gestion avancee des cles API et des quotas.</li><li>Glossaire robuste avec terminologie verrouillee.</li><li>Gestion des conflits de traduction.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Etendre le <code>AiRouter</code> pour supporter les providers cloud optionnels.</li><li>Ajouter une table <code>provider_quotas</code> ou une configuration de limites.</li><li>Renforcer l&#39;interface de gestion du lexique avec conflits et verrouillage.</li><li>Voir <code>docs/volumes/03-AI-Models.md</code>, <code>10-Lexicon.md</code>.</li></ul></li></ul><h4 id="noveltrans-saas-plateforme" tabindex="-1">NovelTrans (SaaS / plateforme) <a class="header-anchor" href="#noveltrans-saas-plateforme" aria-label="Permalink to &quot;NovelTrans (SaaS / plateforme)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Structure de projet resumable par episode.</li><li>File d&#39;attente QA pour erreurs de traduction.</li><li>Termes <code>forbidden</code> et <code>locked</code> avec resolution de conflits.</li><li>RAG translation memory et workspaces.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Persister l&#39;etat du workflow par chapitre dans <code>job_steps</code> pour permettre la reprise.</li><li>Implementer une file d&#39;attente QA dans l&#39;UI.</li><li>Ajouter le champ <code>forbidden</code> aux entrees du lexique.</li><li>Voir <code>docs/volumes/07-Workflow.md</code>, <code>10-Lexicon.md</code>, <code>09-Translation-Memory.md</code>.</li></ul></li></ul><h4 id="translatebookswithllms-desktop-app" tabindex="-1">TranslateBooksWithLLMs (Desktop App) <a class="header-anchor" href="#translatebookswithllms-desktop-app" aria-label="Permalink to &quot;TranslateBooksWithLLMs (Desktop App)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Support de formats varies (EPUB, DOCX, SRT, TXT).</li><li>Preservation du formatage source.</li><li>Systeme de checkpoints / reprise sur incident.</li><li>Aucune limite de taille grace au decoupage.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Decouper les gros EPUB par chapitre avant traduction.</li><li>Sauvegarder l&#39;etat apres chaque step dans SQLite.</li><li>Permettre la reprise apres crash ou fermeture de l&#39;app.</li><li>Voir <code>docs/volumes/07-Workflow.md</code>, <code>13-Export.md</code>, <code>22-Performance.md</code>.</li></ul></li></ul><h4 id="polyglotshelf-service-docker-ui-web-api-rest" tabindex="-1">PolyglotShelf (Service Docker + UI web + API REST) <a class="header-anchor" href="#polyglotshelf-service-docker-ui-web-api-rest" aria-label="Permalink to &quot;PolyglotShelf (Service Docker + UI web + API REST)&quot;">​</a></h4><ul><li><strong>Type</strong> : Pattern / Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Orchestrateur mince qui route vers differents traducteurs selon le format.</li><li>File d&#39;attente SQLite durable et jobs survivant au redemarrage.</li><li>Merge incremental des gros EPUB decoupes par chapitre.</li><li>Glossaires CSV et API REST documentee (OpenAPI).</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Utiliser <code>better-sqlite3</code> comme file d&#39;attente de jobs durable.</li><li>Implementer le merge incremental pour l&#39;export EPUB multi-chapitres.</li><li>Garder l&#39;architecture API REST en vue de la v2.0 serveur.</li><li>Voir <code>docs/volumes/06-Database.md</code>, <code>07-Workflow.md</code>, <code>13-Export.md</code>.</li></ul></li></ul><h3 id="projets-inspiration" tabindex="-1">Projets Inspiration <a class="header-anchor" href="#projets-inspiration" aria-label="Permalink to &quot;Projets Inspiration&quot;">​</a></h3><h4 id="bbook-maker-pypi" tabindex="-1">bbook-maker (PyPI) <a class="header-anchor" href="#bbook-maker-pypi" aria-label="Permalink to &quot;bbook-maker (PyPI)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Configuration provider simple : URL + modele + cle.</li><li>Generation EPUB bilingue.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Garder le formulaire provider minimaliste (URL, modele, cle, temperature).</li><li>Proposer l&#39;export EPUB cote-a-cote comme option.</li></ul></li></ul><h4 id="gptwntranslator" tabindex="-1">gptwntranslator <a class="header-anchor" href="#gptwntranslator" aria-label="Permalink to &quot;gptwntranslator&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Scraping web novels → EPUB automatique.</li><li>Pipeline end-to-end ultra simple.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Offrir un mode &quot;one-shot&quot; pour les cas simples.</li><li>Documenter le flux ideal nouvel utilisateur : source → traduction → EPUB.</li></ul></li></ul><h4 id="transagents-recherche" tabindex="-1">TransAgents (recherche) <a class="header-anchor" href="#transagents-recherche" aria-label="Permalink to &quot;TransAgents (recherche)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Traduction litteraire ultra-longue avec evaluation humaine + LLM.</li><li>Cohérence stylistique sur plusieurs chapitres.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Evaluer la coherence stylistique par comparaison de chapitres.</li><li>Permettre un mode evaluation humaine integree dans l&#39;UI (v1.5+).</li></ul></li></ul><h4 id="repotransagent-recherche" tabindex="-1">RepoTransAgent (recherche) <a class="header-anchor" href="#repotransagent-recherche" aria-label="Permalink to &quot;RepoTransAgent (recherche)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>RAG repository-aware.</li><li>Prompts dynamiques en fonction du contexte.</li><li>Indexation semantique des chapitres precedents.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Enrichir la memoire globale du projet (lexique + resumes + chapitres traduits).</li><li>Utiliser les embeddings Ollama pour l&#39;indexation semantique (v1.5+).</li></ul></li></ul><h4 id="multranslate" tabindex="-1">multranslate <a class="header-anchor" href="#multranslate" aria-label="Permalink to &quot;multranslate&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration (v1.5+).</li><li><strong>Parties interessantes</strong> : <ul><li>Comparaison parallele de providers.</li><li>Detection de langue, historique.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Ajouter un dashboard de benchmark qualite entre providers.</li><li>Comparer plusieurs traductions d&#39;un meme paragraphe.</li></ul></li></ul><h4 id="adaptnmt-recherche" tabindex="-1">adaptNMT (recherche) <a class="header-anchor" href="#adaptnmt-recherche" aria-label="Permalink to &quot;adaptNMT (recherche)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration (v1.5+).</li><li><strong>Parties interessantes</strong> : <ul><li>UI training/eval pour NMT.</li><li>Metriques integrees (BLEU, COMET, etc.).</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Dashboard qualite avec scoring automatique.</li><li>Metriques de calibration sur le jeu de 20 chapitres.</li></ul></li></ul><h4 id="anythingllm-desktop" tabindex="-1">AnythingLLM Desktop <a class="header-anchor" href="#anythingllm-desktop" aria-label="Permalink to &quot;AnythingLLM Desktop&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Workspaces par projet.</li><li>RAG / injection de contexte.</li><li>Historique dans SQLite.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Un workspace = un roman avec son lexique, sa TM, ses parametres modele.</li><li>Voir <code>docs/volumes/04-UI-UX.md</code>, <code>05-Project-Management.md</code>.</li></ul></li></ul><h4 id="chatbox" tabindex="-1">Chatbox <a class="header-anchor" href="#chatbox" aria-label="Permalink to &quot;Chatbox&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>UI de parametres modele par workspace (temperature, context length, system prompt).</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Ecran de configuration des modeles par projet.</li></ul></li></ul><h4 id="sugoi-toolkit" tabindex="-1">Sugoi Toolkit <a class="header-anchor" href="#sugoi-toolkit" aria-label="Permalink to &quot;Sugoi Toolkit&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Decoupage intelligent des phrases.</li><li>File d&#39;attente pour ne pas saturer le modele local.</li><li>Affichage cote-a-cote original/traduction.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Chunking des chapitres en paragraphes / phrases.</li><li>Limiter la concurrence pour Ollama local.</li><li>Vue cote-a-cote dans l&#39;UI.</li></ul></li></ul><h4 id="opennovel-extension-navigateur" tabindex="-1">OpenNovel (extension navigateur) <a class="header-anchor" href="#opennovel-extension-navigateur" aria-label="Permalink to &quot;OpenNovel (extension navigateur)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Zero configuration au premier lancement.</li><li>Scraping + glossaire automatique.</li><li>Chunking intelligent.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Wizard de premier lancement auto-detectant Ollama.</li><li>Extraction automatique de termes candidats au premier import.</li></ul></li></ul><h4 id="lexiconforge-web-app" tabindex="-1">LexiconForge (Web App) <a class="header-anchor" href="#lexiconforge-web-app" aria-label="Permalink to &quot;LexiconForge (Web App)&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration.</li><li><strong>Parties interessantes</strong> : <ul><li>Feedback utilisateur 👍/👎 sur les paragraphes.</li><li>Comparateur de versions (source vs brute vs fan vs IA).</li><li>Footnotes culturelles, exports EPUB enrichis.</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Système de feedback sur les traductions.</li><li>Comparateur de versions cote-a-cote.</li><li>Exports enrichis avec metadonnees et notes.</li></ul></li></ul><h4 id="opus-cat" tabindex="-1">OPUS-CAT <a class="header-anchor" href="#opus-cat" aria-label="Permalink to &quot;OPUS-CAT&quot;">​</a></h4><ul><li><strong>Type</strong> : Inspiration (v1.5+).</li><li><strong>Parties interessantes</strong> : <ul><li>Modeles NMT locaux Marian, offline.</li><li>Plugins TAO (Trados/memoQ).</li></ul></li><li><strong>Recuperation dans NovelTrad</strong> : <ul><li>Option modeles NMT locaux en complement d&#39;Ollama.</li><li>Cas d&#39;usage confidentialite / performance.</li></ul></li></ul><hr><h2 id="concurrents-identifies-mais-non-retenus-comme-reutilisation" tabindex="-1">Concurrents identifies mais non retenus comme reutilisation <a class="header-anchor" href="#concurrents-identifies-mais-non-retenus-comme-reutilisation" aria-label="Permalink to &quot;Concurrents identifies mais non retenus comme reutilisation&quot;">​</a></h2><p>Ces projets ont ete mentionnes dans les retours comme comparables, mais leur architecture ou leur scope est trop eloigne pour une reutilisation directe :</p><table tabindex="0"><thead><tr><th>Projet</th><th>Pourquoi non retenu</th></tr></thead><tbody><tr><td><strong>NovelGenerator</strong></td><td>Generation complete de romans, pas de traduction assistee.</td></tr><tr><td><strong>NovelForge</strong></td><td>Creation assistee avec knowledge graph, scope different.</td></tr><tr><td><strong>GalTransl</strong></td><td>Traduction de Visual Novels (patch VN), pas de pipeline EPUB/roman.</td></tr><tr><td><strong>Chinese Novel Translator</strong></td><td>Projet Reddit communautaire leger ; fonctionnalites deja couvertes par <code>gptwntranslator</code> / <code>OpenNovel</code>.</td></tr><tr><td><strong>clipboard-based translator pipeline</strong></td><td>Projet Reddit leger ; queue/batch deja couvert par <code>Sugoi Toolkit</code>, <code>PolyglotShelf</code>, <code>NovelTrans</code>.</td></tr></tbody></table><hr><h2 id="recommandations-de-reutilisation-par-phase" tabindex="-1">Recommandations de reutilisation par phase <a class="header-anchor" href="#recommandations-de-reutilisation-par-phase" aria-label="Permalink to &quot;Recommandations de reutilisation par phase&quot;">​</a></h2><h3 id="mvp-sprints-1–4" tabindex="-1">MVP (sprints 1–4) <a class="header-anchor" href="#mvp-sprints-1–4" aria-label="Permalink to &quot;MVP (sprints 1–4)&quot;">​</a></h3><ol><li><strong>Project structure</strong> : s&#39;inspirer de <code>honya</code> pour l&#39;arborescence CLI/desktop.</li><li><strong>Parsing</strong> : utiliser <code>mammoth.js</code>, <code>franc</code>, et une librairie EPUB validee.</li><li><strong>Database</strong> : <code>better-sqlite3</code> + pattern Repository deja documente.</li><li><strong>Securite</strong> : appliquer la baseline Electron officielle, valider <code>keytar</code>.</li></ol><h3 id="v1-0-sprints-5–12" tabindex="-1">v1.0 (sprints 5–12) <a class="header-anchor" href="#v1-0-sprints-5–12" aria-label="Permalink to &quot;v1.0 (sprints 5–12)&quot;">​</a></h3><ol><li><strong>Agents</strong> : calquer les roles de <code>LaTeXTrans</code> (Parser/Validator/Terminology/Generator).</li><li><strong>Export EPUB</strong> : etudier <code>epub-translator</code> et <code>PolyglotShelf</code> pour le pipeline et le mode bilingue.</li><li><strong>TM/Glossaire</strong> : s&#39;inspirer d&#39;<code>OmegaT</code> et <code>NovelTrans</code> pour les termes locked/forbidden et la QA queue.</li><li><strong>Checkpoints</strong> : reprendre le pattern de <code>TranslateBooksWithLLMs</code> et de <code>PolyglotShelf</code>.</li></ol><h3 id="v1-5-v2-0" tabindex="-1">v1.5+ / v2.0 <a class="header-anchor" href="#v1-5-v2-0" aria-label="Permalink to &quot;v1.5+ / v2.0&quot;">​</a></h3><ol><li><strong>RAG semantique</strong> : s&#39;inspirer de <code>RepoTransAgent</code> et <code>NovelTrans</code>.</li><li><strong>Feedback utilisateur</strong> : reprendre le 👍/👎 de <code>LexiconForge</code>.</li><li><strong>NMT local</strong> : option <code>OPUS-CAT</code> pour les cas de confidentialite.</li><li><strong>Marketplace plugins</strong> : rester prudent ; commencer par un dossier <code>plugins/</code> local.</li></ol><hr><h2 id="liens-consolides" tabindex="-1">Liens consolidés <a class="header-anchor" href="#liens-consolides" aria-label="Permalink to &quot;Liens consolidés&quot;">​</a></h2><ul><li><a href="https://github.com/oomol-lab/epub-translator" target="_blank" rel="noreferrer">epub-translator</a></li><li><a href="https://pypi.org/project/bbook-maker/" target="_blank" rel="noreferrer">bbook-maker</a></li><li><a href="https://github.com/combobulativedesigns/gptwntranslator" target="_blank" rel="noreferrer">gptwntranslator</a></li><li><a href="https://docs.rs/crate/honya/latest/source/README.md" target="_blank" rel="noreferrer">honya</a></li><li><a href="https://www.sourcepulse.org/projects/16076583" target="_blank" rel="noreferrer">LaTeXTrans</a></li><li><a href="https://arxiv.org/abs/2405.11804" target="_blank" rel="noreferrer">TransAgents</a></li><li><a href="https://arxiv.org/abs/2508.17720" target="_blank" rel="noreferrer">RepoTransAgent</a></li><li><a href="https://github.com/Lifailon/multranslate" target="_blank" rel="noreferrer">multranslate</a></li><li><a href="https://arxiv.org/abs/2403.02367" target="_blank" rel="noreferrer">adaptNMT</a></li><li><a href="https://useanything.com/" target="_blank" rel="noreferrer">AnythingLLM</a></li><li><a href="https://chatboxai.app/" target="_blank" rel="noreferrer">Chatbox</a></li><li><a href="https://omegat.org/" target="_blank" rel="noreferrer">OmegaT</a></li><li><a href="https://github.com/bookfere/Ebook-Translator-Calibre" target="_blank" rel="noreferrer">Ebook Translator for Calibre</a></li><li><a href="https://github.com/anantham/LexiconForge" target="_blank" rel="noreferrer">LexiconForge</a></li><li><a href="https://github.com/Shirochi-stack/Glossarion" target="_blank" rel="noreferrer">Glossarion</a></li><li><a href="https://github.com/YuBing-link/noveltrans" target="_blank" rel="noreferrer">NovelTrans</a></li><li><a href="https://github.com/hydropix/TranslateBooksWithLLMs" target="_blank" rel="noreferrer">TranslateBooksWithLLMs</a></li><li><a href="https://github.com/Helsinki-NLP/OPUS-CAT" target="_blank" rel="noreferrer">OPUS-CAT</a></li><li><a href="https://gitlab.com/sansors/polyglotshelf" target="_blank" rel="noreferrer">PolyglotShelf</a></li></ul>',86)])])}const g=t(i,[["render",l]]);export{h as __pageData,g as default};
